def encode_cyclic(s, alphabet):
    encoded_str = ""
    i = 0
    while i < len(s):
        try:
            char_index = alphabet.index(s[i])
        except ValueError:
            encoded_str += s[i]
        else:
            group_start_index = char_index // 2
            encoded_str += s[i] + alphabet[group_start_index]
        i += 1
    return encoded_str


